    #[test]
    fn certutil_decoded_pe_is_exported_as_recovered_payload() {
        use base64::Engine;

        let mut pe = b"MZ\x90\x00".to_vec();
        pe.resize(1024, 0);
        let b64 = base64::engine::general_purpose::STANDARD.encode(&pe);
        let script =
            format!("echo {b64}>payload.b64\r\ncertutil -decode payload.b64 payload.dll\r\n");
        let report = analyze(script.as_bytes(), &Config::default());

        assert!(
            report
                .recovered_pe
                .iter()
                .any(|(label, blob)| label.contains("certutil") && blob == &pe),
            "certutil-decoded PE was not exported: {:?}",
            report
                .recovered_pe
                .iter()
                .map(|(label, blob)| (label.as_str(), blob.len()))
                .collect::<Vec<_>>()
        );
    }

    #[test]
    fn certutil_decoded_pe_command_strings_are_scanned_for_behavior() {
        use base64::Engine;

        let mut pe = b"MZ\x90\x00".to_vec();
        pe.resize(512, 0);
        pe.extend_from_slice(b"vssadmin delete shadows /all /quiet");
        pe.resize(1024, 0);
        let b64 = base64::engine::general_purpose::STANDARD.encode(&pe);
        let script =
            format!("echo {b64}>payload.b64\r\ncertutil -decode payload.b64 payload.dll\r\n");
        let report = analyze(script.as_bytes(), &Config::default());

        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::AntiRecovery { action } if action == "vssadmin-delete-shadows"
                )
            }),
            "decoded PE behavior string was not scanned: {:?}",
            report.traits
        );
    }

    #[test]
    fn certutil_decoded_pe_utf16_command_strings_are_scanned_for_behavior() {
        use base64::Engine;

        let mut pe = b"MZ\x90\x00".to_vec();
        pe.resize(512, 0);
        for unit in "Set-MpPreference -DisableRealtimeMonitoring $true".encode_utf16() {
            pe.extend_from_slice(&unit.to_le_bytes());
        }
        pe.resize(1024, 0);
        let b64 = base64::engine::general_purpose::STANDARD.encode(&pe);
        let script =
            format!("echo {b64}>payload.b64\r\ncertutil -decode payload.b64 payload.dll\r\n");
        let report = analyze(script.as_bytes(), &Config::default());

        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::DefenderEvasion { action, .. }
                        if action == "setmp-disablerealtimemonitoring"
                )
            }),
            "decoded PE UTF-16 behavior string was not scanned: {:?}",
            report.traits
        );
    }

    #[test]
    fn certutil_decoded_pe_export_has_own_quota() {
        use crate::env::{DecodeKind, Environment, FsEntry};

        let mut env = Environment::new(&Config::default());
        for i in 0..16 {
            env.recovered_pe.push((format!("other-{i}"), vec![i as u8]));
        }
        let mut pe = b"MZ\x90\x00".to_vec();
        pe.resize(1024, 0);
        env.modified_filesystem.insert(
            "payload.dll".to_string(),
            FsEntry::Decoded {
                content: pe.clone(),
                src: "payload.b64".to_string(),
                method: DecodeKind::Base64,
            },
        );

        crate::collect_decoded_pe_artifacts(&mut env);

        assert!(
            env.recovered_pe
                .iter()
                .any(|(label, blob)| label.contains("certutil-decoded-payload.dll") && blob == &pe),
            "certutil decoded PE was skipped because other recovered blobs filled the global quota: {:?}",
            env.recovered_pe
                .iter()
                .map(|(label, blob)| (label.as_str(), blob.len()))
                .collect::<Vec<_>>()
        );
    }

    #[test]
    fn certutil_decode_self_basename_resolves_with_input_path() {
        use base64::Engine;

        let mut pe = b"MZ\x90\x00".to_vec();
        pe.resize(1024, 0);
        let b64 = base64::engine::general_purpose::STANDARD.encode(&pe);
        let script = format!(
            "certutil -decode -f %~nx0 payload.exe\r\n-----BEGIN CERTIFICATE-----\r\n{b64}\r\n-----END CERTIFICATE-----\r\n"
        );
        let report = crate::analyze_with_path(
            script.as_bytes(),
            &Config::default(),
            std::path::Path::new(r"C:\Users\al\Downloads\invoice.cmd"),
        );

        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::CertutilDecode { src, dst, src_resolved }
                        if src == "invoice.cmd" && dst == "payload.exe" && *src_resolved
                )
            }),
            "self-basename certutil decode did not resolve: {:?}",
            report.traits
        );
        assert!(
            report
                .recovered_pe
                .iter()
                .any(|(label, blob)| label.contains("certutil") && blob == &pe),
            "self-decoded PE was not exported: {:?}",
            report
                .recovered_pe
                .iter()
                .map(|(label, blob)| (label.as_str(), blob.len()))
                .collect::<Vec<_>>()
        );
    }

    #[test]
    fn multiline_pe_base64_carrier_block_is_summarized() {
        use base64::Engine;

        let mut pe = b"MZ\x90\x00".to_vec();
        pe.resize(12_289, 0);
        let b64 = base64::engine::general_purpose::STANDARD.encode(&pe);
        let wrapped = b64
            .as_bytes()
            .chunks(256)
            .map(|chunk| std::str::from_utf8(chunk).expect("ascii"))
            .collect::<Vec<_>>()
            .join("\r\n");
        let script = format!(
            "findstr /V marker \"%0\" > payload.b64\r\n{wrapped}\r\ncertutil -decode payload.b64 payload.dll\r\n"
        );
        let report = analyze(script.as_bytes(), &Config::default());

        assert!(
            report
                .deobfuscated
                .contains("omitted multiline base64 PE carrier"),
            "multiline PE carrier was not summarized:\n{}",
            report.deobfuscated
        );
        assert!(
            !report.deobfuscated.contains(&b64[..256]),
            "raw multiline PE base64 carrier leaked into deob output"
        );
        let tail = b64
            .as_bytes()
            .rchunks(256)
            .next()
            .and_then(|chunk| std::str::from_utf8(chunk).ok())
            .expect("ascii");
        assert!(
            !report.deobfuscated.lines().any(|line| line.trim() == tail),
            "short final base64 carrier line leaked into deob output"
        );
        assert!(
            report
                .recovered_pe
                .iter()
                .any(|(label, blob)| label.contains("embedded-base64-pe") && blob == &pe),
            "summarized multiline PE carrier was not exported: {:?}",
            report
                .recovered_pe
                .iter()
                .map(|(label, blob)| (label.as_str(), blob.len()))
                .collect::<Vec<_>>()
        );
    }

