        let noisy_for_set = "%NoiseA%f%NoiseB%%NoiseC%o%NoiseD%%NoiseE%r%NoiseF% /l %%z  %NoiseK%i%NoiseL%n%NoiseM% (1, 1, 1) do ( %NoiseN%s%NoiseO%%NoiseP%e%NoiseQ%%NoiseR%t%NoiseS% \"%NoiseT%v%NoiseU%=%NoiseV%t%NoiseW%\" )";
